module gray_counter_3bit(
    input clk,
    input rst,
    output [2:0] count
);

    reg [2:0] counter_reg;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (rst) begin
            counter_reg <= 3'b000;
        end else begin
            counter_reg <= counter_reg + 1;
        end
    end

    assign count = counter_reg ^ (counter_reg >> 1);

endmodule
